-- Add politicas_privacidad and terminos_condiciones keys to site_config
-- for CMS-editable legal documents.

INSERT INTO site_config (key, value)
VALUES (
  'politicas_privacidad',
  to_jsonb('<section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">1. Responsable del Tratamiento</h2><p><strong>Identificación:</strong> El Legado Catering y Eventos</p><p><strong>Email:</strong> catering.ellegado@gmail.com</p><p><strong>Sitio web:</strong> https://ellegado.vercel.app</p></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">2. Datos que Recopilamos</h2><ul class="list-disc pl-5 space-y-1"><li><strong>Datos de contacto:</strong> nombre, teléfono, email.</li><li><strong>Datos del evento:</strong> tipo, invitados, servicios solicitados, presupuesto.</li><li><strong>Datos de navegación:</strong> IP, navegador, páginas visitadas (cookies).</li></ul></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">3. Finalidad del Tratamiento</h2><p>Utilizamos sus datos para procesar cotizaciones, contactarle respecto a su evento, gestionar la relación comercial y mejorar nuestros servicios. Base legal: su consentimiento (arts. 5° y 6° Ley 25.326).</p></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">4. Plazo de Conservación</h2><ul class="list-disc pl-5 space-y-1"><li><strong>Cotizaciones:</strong> 2 años desde su generación.</li><li><strong>Datos de clientes:</strong> 5 años desde la última interacción.</li><li><strong>Cookies:</strong> 12 meses.</li></ul></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">5. Derechos del Titular</h2><p>Conforme a la Ley 25.326, usted tiene derecho a <strong>acceder, rectificar, suprimir</strong> sus datos u <strong>oponerse</strong> al tratamiento. Para ejercerlos, escriba a catering.ellegado@gmail.com. Responderemos dentro de 10 días hábiles.</p><p class="mt-2">Puede presentar un reclamo ante la <strong>Dirección Nacional de Protección de Datos Personales</strong> en argentina.gob.ar/justicia/dnpdp.</p></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">6. Cookies</h2><p>Utilizamos cookies esenciales para el funcionamiento del cotizador y analíticas. Puede configurar su navegador para rechazarlas. Al aceptar, consiente su uso conforme a esta política.</p></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">7. Transferencia Internacional de Datos</h2><p>Utilizamos Supabase como infraestructura (servidores en EE.UU.) bajo acuerdos de procesamiento de datos. Al usar el sitio, usted consiente esta transferencia (art. 12 Ley 25.326).</p></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">8. Compartición con Terceros</h2><p>No compartimos datos con fines comerciales. Solo con Supabase (infraestructura) y WhatsApp/Meta (cuando inicia una conversación).</p></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">9. Seguridad</h2><p>Implementamos HTTPS/TLS, CSP, autenticación segura y RLS en base de datos para proteger sus datos.</p></section>'::text)
)
ON CONFLICT (key) DO NOTHING;

INSERT INTO site_config (key, value)
VALUES (
  'terminos_condiciones',
  to_jsonb('<section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">1. Aceptación de los Términos</h2><p>Al acceder y utilizar el sitio web, incluyendo el cotizador online, usted acepta estos Términos y Condiciones. Si no está de acuerdo, no utilice nuestros servicios.</p></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">2. Descripción del Servicio</h2><p>Ofrecemos servicios de catering para eventos. Nuestro sitio permite explorar productos, generar cotizaciones estimadas y contactarnos vía WhatsApp.</p></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">3. Cotizaciones Online</h2><ul class="list-disc pl-5 space-y-1"><li>Las cotizaciones son <strong>estimaciones referenciales</strong>.</li><li>Los precios pueden variar según fecha, ubicación y requerimientos.</li><li>No constituyen una reserva hasta confirmación por escrito.</li><li>Los precios están expresados en Pesos Argentinos (ARS).</li></ul></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">4. Proceso de Reserva</h2><ol class="list-decimal pl-5 space-y-1"><li>El usuario genera una cotización.</li><li>El Legado contacta para confirmar detalles y disponibilidad.</li><li>Se envía propuesta formal con precios definitivos.</li><li>El usuario acepta y realiza el pago de seña.</li><li>Se confirma la reserva y se coordinan detalles finales.</li></ol></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">5. Política de Cancelación</h2><ul class="list-disc pl-5 space-y-1"><li>Más de 30 días: devolución del 50% de la seña.</li><li>Entre 15 y 30 días: la seña no es reembolsable.</li><li>Menos de 15 días: se cobra el 100% del servicio.</li></ul></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">6. Responsabilidades del Usuario</h2><p>El usuario se compromete a proporcionar información veraz, no usar el cotizador con fines maliciosos, respetar plazos de pago e informar restricciones alimentarias con anticipación.</p></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">7. Comunicación vía WhatsApp</h2><p>Al usar nuestro enlace de WhatsApp, la comunicación se rige por la política de privacidad de Meta Platforms, Inc.</p></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">8. Legislación Aplicable</h2><p>Estos términos se rigen por la legislación argentina. Las partes se someten a los tribunales de la Ciudad Autónoma de Buenos Aires. Conforme a la Ley 24.240 de Defensa del Consumidor.</p></section><section><h2 class="font-serif text-2xl text-brand-copper mb-3 font-medium">9. Contacto</h2><p><strong>Email:</strong> catering.ellegado@gmail.com</p></section>'::text)
)
ON CONFLICT (key) DO NOTHING;
